272: template <typename EntityClassT>
273: std::vector<UUID> IAccessStorage::findAll() const
274: {
275:     if constexpr (std::is_same_v<EntityClassT, IAccessEntity>)
276:         return findAllImpl();
277:     else
278:         return findAllImpl(EntityClassT::TYPE);
279: }
280: 
281: 
282: template <typename EntityClassT>
283: std::shared_ptr<const EntityClassT> IAccessStorage::read(const UUID & id, bool throw_if_not_exists) const
284: {
285:     auto entity = readImpl(id, throw_if_not_exists);
286:     if constexpr (std::is_same_v<EntityClassT, IAccessEntity>)
287:         return entity;
288:     else
289:     {
290:         if (!entity)
291:             return nullptr;
292:         if (auto ptr = typeid_cast<std::shared_ptr<const EntityClassT>>(entity))
293:             return ptr;
294:         throwBadCast(id, entity->getType(), entity->getName(), EntityClassT::TYPE);
295:     }
296: }
297: 
298: 
299: template <typename EntityClassT>
300: std::shared_ptr<const EntityClassT> IAccessStorage::read(const String & name, bool throw_if_not_exists) const
301: {
302:     if (auto id = find<EntityClassT>(name))
303:         return read<EntityClassT>(*id, throw_if_not_exists);
304:     if (throw_if_not_exists)
305:         throwNotFound(EntityClassT::TYPE, name);
306:     else
307:         return nullptr;
308: }
309: 
310: 
311: template <typename EntityClassT>
312: std::vector<AccessEntityPtr> IAccessStorage::read(const std::vector<UUID> & ids, bool throw_if_not_exists) const
313: {
314:     std::vector<AccessEntityPtr> result;
315:     result.reserve(ids.size());
316: 
317:     for (const auto & id : ids)
318:         result.push_back(read<EntityClassT>(id, throw_if_not_exists));
319: 
320:     return result;
321: }
322: 
323: 
324: template <typename EntityClassT>
325: std::shared_ptr<const EntityClassT> IAccessStorage::tryRead(const UUID & id) const
326: {
327:     return read<EntityClassT>(id, false);
328: }
329: 
330: 
331: template <typename EntityClassT>
332: std::shared_ptr<const EntityClassT> IAccessStorage::tryRead(const String & name) const
333: {
334:     return read<EntityClassT>(name, false);
335: }
336: 
337: template <typename EntityClassT>
338: std::vector<std::pair<UUID, std::shared_ptr<const EntityClassT>>> IAccessStorage::readAllWithIDs() const
339: {
340:     std::vector<std::pair<UUID, std::shared_ptr<const EntityClassT>>> entities;
341:     for (const auto & id : findAll<EntityClassT>())
342:     {
343:         if (auto entity = tryRead<EntityClassT>(id))
344:             entities.emplace_back(id, entity);
345:     }
346:     return entities;
347: }
