31: 
32:     /// Sets that the policy is permissive.
33:     /// A row is only accessible if at least one of the permissive policies passes,
34:     /// in addition to all the restrictive policies.
35:     void setPermissive(bool permissive_ = true) { setRestrictive(!permissive_); }
36:     bool isPermissive() const { return !isRestrictive(); }
