35: /// Provides fast access to row policies' conditions for a specific user and tables.
36: class EnabledRowPolicies
37: {
38: public:
39:     struct Params
40:     {
41:         UUID user_id;
42:         boost::container::flat_set<UUID> enabled_roles;
43: 
44:         auto toTuple() const { return std::tie(user_id, enabled_roles); }
45:         friend bool operator ==(const Params & lhs, const Params & rhs) { return lhs.toTuple() == rhs.toTuple(); }
46:         friend bool operator !=(const Params & lhs, const Params & rhs) { return !(lhs == rhs); }
47:         friend bool operator <(const Params & lhs, const Params & rhs) { return lhs.toTuple() < rhs.toTuple(); }
48:         friend bool operator >(const Params & lhs, const Params & rhs) { return rhs < lhs; }
49:         friend bool operator <=(const Params & lhs, const Params & rhs) { return !(rhs < lhs); }
50:         friend bool operator >=(const Params & lhs, const Params & rhs) { return !(lhs < rhs); }
51:     };
52: 
53:     EnabledRowPolicies();
54:     ~EnabledRowPolicies();
55: 
56:     /// Returns prepared filter for a specific table and operations.
57:     /// The function can return nullptr, that means there is no filters applied.
58:     /// The returned filter can be a combination of the filters defined by multiple row policies.
59:     RowPolicyFilterPtr getFilter(const String & database, const String & table_name, RowPolicyFilterType filter_type) const;
60:     RowPolicyFilterPtr getFilter(const String & database, const String & table_name, RowPolicyFilterType filter_type, RowPolicyFilterPtr combine_with_filter) const;
61: 
62: private:
63:     friend class RowPolicyCache;
64:     explicit EnabledRowPolicies(const Params & params_);
65: 
66:     struct MixedFiltersKey
67:     {
68:         std::string_view database;
69:         std::string_view table_name;
70:         RowPolicyFilterType filter_type;
71: 
72:         auto toTuple() const { return std::tie(database, table_name, filter_type); }
73:         friend bool operator==(const MixedFiltersKey & left, const MixedFiltersKey & right) { return left.toTuple() == right.toTuple(); }
74:         friend bool operator!=(const MixedFiltersKey & left, const MixedFiltersKey & right) { return left.toTuple() != right.toTuple(); }
75:     };
76: 
77:     struct Hash
78:     {
79:         size_t operator()(const MixedFiltersKey & key) const;
80:     };
81: 
82:     using MixedFiltersMap = std::unordered_map<MixedFiltersKey, RowPolicyFilterPtr, Hash>;
83: 
84:     const Params params;
85:     mutable boost::atomic_shared_ptr<const MixedFiltersMap> mixed_filters;
86: };
87: 
88: }
