24:         auto toTuple() const { return std::tie(current_roles, current_roles_with_admin_option); }
25:         friend bool operator ==(const Params & lhs, const Params & rhs) { return lhs.toTuple() == rhs.toTuple(); }
26:         friend bool operator !=(const Params & lhs, const Params & rhs) { return !(lhs == rhs); }
27:         friend bool operator <(const Params & lhs, const Params & rhs) { return lhs.toTuple() < rhs.toTuple(); }
28:         friend bool operator >(const Params & lhs, const Params & rhs) { return rhs < lhs; }
29:         friend bool operator <=(const Params & lhs, const Params & rhs) { return !(rhs < lhs); }
30:         friend bool operator >=(const Params & lhs, const Params & rhs) { return !(lhs < rhs); }
31:     };
